1	\chapter{Sheaves of $k$-modules: sheafification, Ext, and the structure sheaf as a sheaf of $k$-modules}
2	\label{chap:Cohomology_StructureSheafModuleK}
3	
4	This chapter implements Phase~A step~5 of \texttt{STRATEGY.md}: equipping $H^1(C, \struct C)$ with a $k$-vector-space structure when $C$ is a scheme over $\Spec k$. The route is through Mathlib's general $\Linear k$ enrichment of $\Sheaf(\opens X, \ModuleCat k)$ together with \lstinline{CategoryTheory.Abelian.Ext.instModule}, which automatically provides $\Module k$ on $\Ext$ groups in any $\Linear k$ abelian category. The chapter introduces no protected declarations: every instance and definition here is auxiliary, supporting the construction of $H^1(C, \struct C)$ in Definition~\ref{def:genus}.
5	
6	The chapter is split into two sections of work. Section~\ref{sec:moduleK_prereqs} and~\ref{sec:moduleK_ext} (the iteration~005 work) provide the typeclass plumbing — the $\HasSheafify$ and $\HasExt$ instances on $\Sheaf(\opens X, \ModuleCat k)$. Section~\ref{sec:scheme_toModuleKSheaf} (the iteration~006 work) provides the \emph{substantive} content of Phase~A step~5: the $\ModuleCat k$-valued structure sheaf $\toModuleKSheaf C$ for $C : \mathrm{Over}\,(\Spec k)$, viewing $\struct C$ as a sheaf of $k$-modules via the structure morphism. Together these complete Phase~A step~5; the final remaining piece for an honest definition of $\genus C$ as $\dim_k H^1(C, \struct C)$ is then Phase~A step~6 (Serre finiteness, multi-iteration).
7	
8	A discovery probe of Mathlib \texttt{b80f227} (logged in \texttt{task\_pending.md}) confirms that the four typeclass pieces of Sections~\ref{sec:moduleK_prereqs}–\ref{sec:moduleK_ext} are already in Mathlib (no new mathematical content; only universe-pinned packaging) and that the eight pieces of Section~\ref{sec:scheme_toModuleKSheaf} type-check end-to-end (~80 LOC; one short proof per piece). After this chapter lands, the typeclass chain \[ \HasSheafify \to \HasExt \to \Linear k \to \mathtt{Ext.instModule} \] is in place and $\toModuleKSheaf C$ provides the actual carrier on which it operates; the $\Module k$ instance on $H^1(C, \struct C) := (\toModuleKSheaf C).\mathtt H\,1$ is then automatic.
9	
10	\section{Sheafification of $\ModuleCat k$-valued sheaves on opens}
11	\label{sec:moduleK_prereqs}
12	
13	\begin{theorem}[Sheafification on the topology of opens, $\ModuleCat k$-valued]
14	  \label{thm:HasSheafify_Opens_ModuleCatK}
15	  \lean{AlgebraicGeometry.Cohomology.instHasSheafify_Opens_ModuleCatK}
16	  \leanok
17	  Let $k$ be a commutative ring and $X$ a topological space. Then the Grothendieck topology of opens of $X$ has
18	  \[
19	    \mathtt{HasSheafify}(\opens(X), \ModuleCat\, k).
20	  \]
21	\end{theorem}
22	
23	\begin{proof}
24	  \leanok
25	  Mathlib's general sheafification API constructs \lstinline{HasSheafify J A} whenever \lstinline{HasWeakSheafify J A} holds and the resulting sheafification preserves finite limits. For \lstinline{J = Opens.grothendieckTopology X} and \lstinline{A = ModuleCat k} both prerequisites are wired in Mathlib (small-site sheafification on a concrete category, plus exactness of $\ModuleCat k$-valued sheafification). The instance is therefore inferable; the prover's task is to reproduce the universe pinning that succeeded for the iter-004 $\AddCommGrpCat$ analogue (Theorem~\ref{thm:HasSheafify_Opens_AddCommGrp}).
26	\end{proof}
27	
28	\section{$\Ext$ for $\ModuleCat k$-valued sheaves on opens}
29	\label{sec:moduleK_ext}
30	
31	\begin{theorem}[$\Ext$ on the topology of opens, $\ModuleCat k$-valued]
32	  \label{thm:HasExt_Sheaf_Opens_ModuleCatK}
33	  \lean{AlgebraicGeometry.Cohomology.instHasExt_Sheaf_Opens_ModuleCatK}
34	  \uses{thm:HasSheafify_Opens_ModuleCatK}
35	  \leanok
36	  Let $k$ be a commutative ring and $X$ a topological space. Then the category $\Sheaf(\opens(X), \ModuleCat k)$ has
37	  \[
38	    \mathtt{HasExt.\{u+1\}}\bigl(\Sheaf(\opens(X), \ModuleCat k)\bigr).
39	  \]
40	\end{theorem}
41	
42	\begin{proof}
43	  \uses{thm:HasSheafify_Opens_ModuleCatK}
44	  \leanok
45	  $\ModuleCat k$ is abelian. The sheaf category $\Sheaf(J, A)$ inherits an abelian structure from an abelian $A$ once \lstinline{HasSheafify J A} holds (Theorem~\ref{thm:HasSheafify_Opens_ModuleCatK}). Mathlib's \lstinline{CategoryTheory.HasExt.standard} produces a \lstinline{HasExt} instance from any abelian category. The universe annotation \lstinline{HasExt.\{u+1\}} matches the unique morphism universe of \lstinline{Sheaf (Opens.gT X) (ModuleCat.\{u\} k)}, mirroring the iter-004 $\AddCommGrpCat$ analogue (Theorem~\ref{thm:HasExt_Sheaf_Opens_AddCommGrp}).
46	\end{proof}
47	
48	\section{The structure sheaf of a $\Spec k$-scheme as a sheaf of $k$-modules}
49	\label{sec:scheme_toModuleKSheaf}
50	
51	This section provides the substantive content of Phase~A step~5: for $C : \Over\,(\Spec\,(\CommRingCat\,k))$, equipping the structure sheaf $\struct C$ with a sheaf-of-$k$-modules structure via the algebra map induced by the structure morphism $C.\mathrm{hom} : C.\mathrm{left} \to \Spec\,(\CommRingCat\,k)$. Together with the typeclass plumbing of Sections~\ref{sec:moduleK_prereqs}–\ref{sec:moduleK_ext} and Mathlib's \lstinline{CategoryTheory.Abelian.Ext.instModule}, this completes the typeclass chain that gives $H^1(C, \struct C)$ a $\Module k$ structure.
52	
53	\subsection{The algebra map from the structure morphism}
54	
55	For each open $U \subseteq C.\mathrm{left}$, the structure morphism induces a chain of ring maps
56	\[
57	  k \xrightarrow{(\Gamma\!\Spec\!\mathrm{Iso}\,k)^{-1}} \Gamma(\Spec\,k, \top) \xrightarrow{C.\mathrm{hom}.\mathrm{app}\,\top} \Gamma(C.\mathrm{left}, C.\mathrm{hom}^{-1}\top) \xrightarrow{\rho} \Gamma(C.\mathrm{left}, U),
58	\]
59	where $\rho$ is the restriction along $U \le C.\mathrm{hom}^{-1}\top = \top$. Mathlib's \lstinline{Scheme.\Gamma SpecIso} provides the first iso, and the rest is the ordinary \lstinline{Scheme.Hom.app} together with the action of the presheaf on the inclusion $U \le \top$.
60	
61	\begin{definition}[Algebra map on a section]
62	  \label{def:Scheme_kToSection}
63	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.kToSection}
64	  \uses{def:Scheme_toAbSheaf}
65	  \leanok
66	  Let $k$ be a commutative ring and $C : \Over\,(\Spec\,(\CommRingCat\,k))$. For any open $U$ of $C.\mathrm{left}$, define
67	  \[
68	    \mathtt{kToSection}\,C\,U \;\colon\; \CommRingCat\,k \;\longrightarrow\; \Gamma(C.\mathrm{left}, U)
69	  \]
70	  to be the composition $(\Gamma\!\Spec\!\mathrm{Iso}\,(\CommRingCat\,k))^{-1} \circ (C.\mathrm{hom}.\mathrm{app}\,\top) \circ \rho$, where $\rho$ is the restriction map of $C.\mathrm{left}$ from $\top$ to $U$.
71	\end{definition}
72	
73	\begin{definition}[Algebra structure on a section]
74	  \label{def:Scheme_algebraSection}
75	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.algebraSection}
76	  \uses{def:Scheme_kToSection}
77	  \leanok
78	  The ring map $\mathtt{kToSection}\,C\,U$ exhibits $\Gamma(C.\mathrm{left}, U)$ as a $k$-algebra. We register the resulting $\Algebra\,k\,(\Gamma(C.\mathrm{left}, U))$ instance via \lstinline{RingHom.toAlgebra}.
79	\end{definition}
80	
81	\begin{lemma}[Defining identity for the algebra map]
82	  \label{lem:Scheme_algebraMap_eq_kToSection}
83	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.algebraMap_eq_kToSection}
84	  \uses{def:Scheme_algebraSection}
85	  \leanok
86	  Under the algebra structure of Definition~\ref{def:Scheme_algebraSection},
87	  \[
88	    \mathtt{algebraMap}\,k\,(\Gamma(C.\mathrm{left}, U)) \;=\; (\mathtt{kToSection}\,C\,U).\mathrm{hom}.
89	  \]
90	\end{lemma}
91	
92	\begin{proof}
93	  \uses{def:Scheme_algebraSection}
94	  \leanok
95	  Definitionally true: \lstinline{RingHom.toAlgebra}$\,(f).\mathrm{algebraMap} = f$.
96	\end{proof}
97	
98	\subsection{Naturality of the algebra map}
99	
100	\begin{lemma}[Restriction is compatible with the algebra map]

450	After Theorems~\ref{thm:Scheme_module_finite_HModule_zero} and~\ref{thm:Scheme_module_finite_HModule_prime_zero} the iter-038 H⁰ $\Module\,k$-finite transports cover the abstract sheaf setting. Iter-039 lands their direct curve specialisations to $F := \toModuleKSheaf\,C$ for $C : \Over\,(\Spec\,(\CommRingCat.\mathrm{of}\,k))$, completing the $\Module\,k$-finite transport ladder at degree $0$ for the curve setting and setting up the iter-040+ Hom-from-affine-evaluation finiteness inputs the cover-evaluation chain consumes.
451	The bodies are pure dot-notation method-call wrappers around iter-038's transports; they rely on the iter-005 instances $\HasSheafify\,(\Opens.\gT\,C.\mathtt{left}.\toTopCat)\,(\ModuleCat\,k)$ and $\HasExt$ on the corresponding sheaf category being auto-resolved by \lstinline{inferInstance}.
452	
453	\begin{theorem}\leanok
454	[Curve specialisation of the $\HModule\,k\,F\,0$ $\Module\,k$-finite transport]
455	  \label{thm:Scheme_module_finite_HModule_zero_curve}
456	  \lean{AlgebraicGeometry.Scheme.module_finite_HModule_zero_curve}
457	  \uses{thm:Scheme_module_finite_HModule_zero, def:Scheme_toModuleKSheaf}
458	  Let $k$ be a field and $C : \Over\,(\Spec\,(\CommRingCat.\mathrm{of}\,k))$. If the $k$-linear Hom group $((\mathtt{constantSheaf}\,(\Opens.\gT\,C.\mathtt{left}.\toTopCat)\,(\ModuleCat\,k)).\mathrm{obj}\,(\ModuleCat.\mathrm{of}\,k\,k) \to \toModuleKSheaf\,C)$ is $\Module.\mathrm{Finite}$ over $k$, then $\HModule\,k\,(\toModuleKSheaf\,C)\,0$ is $\Module.\mathrm{Finite}$ over $k$.
459	\end{theorem}
460	
461	\begin{proof}
462	  \uses{thm:Scheme_module_finite_HModule_zero}
463	  \leanok
464	  Direct dot-notation method-call \lstinline{Scheme.module_finite_HModule_zero k _}: the abstract Theorem~\ref{thm:Scheme_module_finite_HModule_zero} is applied with $J := \Opens.\gT\,C.\mathtt{left}.\toTopCat$ (auto-inferred via the iter-005 \lstinline{instHasSheafify_Opens_ModuleCatK} and \lstinline{instHasExt_Sheaf_Opens_ModuleCatK} instances) and $F := \toModuleKSheaf\,C$ (filled by \lstinline{_} from the result type). The typeclass-style hypothesis on the Hom group is propagated unchanged.
465	\end{proof}
466	
467	\begin{theorem}\leanok
468	[Curve specialisation of the $\HModulePrime\,k\,F\,0\,U$ $\Module\,k$-finite transport]
469	  \label{thm:Scheme_module_finite_HModule_prime_zero_curve}
470	  \lean{AlgebraicGeometry.Scheme.module_finite_HModule'_zero_curve}
471	  \uses{thm:Scheme_module_finite_HModule_prime_zero, def:Scheme_toModuleKSheaf}
472	  Let $k$ be a field, $C : \Over\,(\Spec\,(\CommRingCat.\mathrm{of}\,k))$, and $U$ an open of $C.\mathtt{left}.\toTopCat$. If the $k$-linear Hom group $((\mathtt{presheafToSheaf}\,(\Opens.\gT\,C.\mathtt{left}.\toTopCat)\,(\ModuleCat\,k)).\mathrm{obj}\,((\yoneda \circ \free_k).\mathrm{obj}\,U) \to \toModuleKSheaf\,C)$ is $\Module.\mathrm{Finite}$ over $k$, then $\HModulePrime\,k\,(\toModuleKSheaf\,C)\,0\,U$ is $\Module.\mathrm{Finite}$ over $k$.
473	\end{theorem}
474	
475	\begin{proof}
476	  \uses{thm:Scheme_module_finite_HModule_prime_zero}
477	  \leanok
478	  Direct dot-notation method-call \lstinline{Scheme.module_finite_HModule'_zero k _ U}: the abstract Theorem~\ref{thm:Scheme_module_finite_HModule_prime_zero} is applied with the same auto-inferred topology / instance setup as Theorem~\ref{thm:Scheme_module_finite_HModule_zero_curve}, with $X := U$ and $F := \toModuleKSheaf\,C$. The Hom-group hypothesis is propagated unchanged.
479	\end{proof}
480	
481	\begin{remark}[Use in the cover-evaluation chain]
482	  For an affine cover $X = U_1 \cup U_2$ packaged as an \lstinline{AffineCoverMVSquare} (iter-028), the four corners of the Mayer-Vietoris square are $X_1 = U_1$, $X_2 = U_2$, $X_3 = U_1 \cap U_2$, $X_4 = \top$. The iter-029/030 LES on $\HModulePrime\,k\,(\toModuleKSheaf\,C)$ at degrees $(0, 1)$ then reads
483	  \[
484	    \HModulePrime^0(X_4) \to \HModulePrime^0(X_2) \oplus \HModulePrime^0(X_3) \to \HModulePrime^0(X_1) \to \HModulePrime^1(X_4) \to \cdots
485	  \]
486	  The iter-035 corner-bridge identifies $\HModulePrime^n(X_4)$ with $\HModule\,k\,(\toModuleKSheaf\,C)\,n$. After future affine vanishing (Mathlib gap; queued for iter-040+), $\HModulePrime^1(X_2) = \HModulePrime^1(X_3) = 0$, so the LES yields a short exact sequence presenting $\HModule^1$ as a cokernel of $\HModulePrime^0(X_2) \oplus \HModulePrime^0(X_3) \to \HModulePrime^0(X_1)$. The iter-039 curve specialisations~\ref{thm:Scheme_module_finite_HModule_zero_curve} and~\ref{thm:Scheme_module_finite_HModule_prime_zero_curve} then propagate $\Module\,k$-finiteness through the H⁰ pieces (one application per affine corner), and iter-037's \lstinline{module_finite_HModule_of_HModule'_X₄_curve} carries the result up to $\HModule\,k\,(\toModuleKSheaf\,C)\,1$, which is the genus carrier (Definition~\ref{def:genus}).
487	\end{remark}
488	
489	\section{Affine cohomology vanishing carrier predicate (iter-040)}
490	\label{sec:IsAffineHModuleVanishing_iter040}
491	
492	Iter-038/039 deliver the $H^0$ side of the $\Module\,k$-finite transport: given finiteness of the relevant Hom group, $\HModule^0$ is $\Module\,k$-finite. The cover-evaluation chain on a curve also requires the $H^{>0}$ side, which on an affine open is the geometric statement $H^i(U, F) = 0$ for $i > 0$ (Serre vanishing on affines). Mathlib does not yet provide this for $\ModuleCat\,k$-valued sheaf cohomology, so we package it as a hypothesis: a \texttt{class} that consumers can either receive as an instance argument (when a producer instance is available) or supply explicitly at the call site.
493	
494	\begin{theorem}\leanok
495	[Affine cohomology vanishing carrier predicate]
496	  \label{thm:Scheme_IsAffineHModuleVanishing}
497	  \lean{AlgebraicGeometry.Scheme.IsAffineHModuleVanishing}
498	  \uses{def:Scheme_HModule_prime}
499	  Let $k$ be a field, $C : \Over\,(\Spec\,(\CommRingCat.\mathrm{of}\,k))$, and $F$ a sheaf of $\ModuleCat\,k$ on $\Opens\,(C.\mathtt{left}.\toTopCat)$. The class \lstinline{IsAffineHModuleVanishing k C F} bundles the proposition that for every affine open $U$ of $C.\mathtt{left}$ and every degree $i > 0$, the open-evaluation cohomology $\HModulePrime\,k\,F\,i\,U$ is a subsingleton (equivalently, the zero $k$-module).
500	\end{theorem}
501	
502	\begin{proof}
503	  \leanok
504	  Definitional: a \texttt{class} with a single field \lstinline{subsingleton_HModule' : \forall \{U\}, IsAffineOpen U \to \forall i, 0 < i \to Subsingleton (HModule' k F i U)}. The choice of \lstinline{Subsingleton} (rather than the categorical \lstinline{Limits.IsZero}) is mandated by the iter-014 typing: $\HModulePrime$ returns a \lstinline{Type u} (the underlying type of an $\Ext$ group) rather than a \lstinline{ModuleCat} object, so categorical \lstinline{IsZero} does not directly apply. The two formulations are nevertheless equivalent via Mathlib's \lstinline{ModuleCat.subsingleton_of_isZero}; the \lstinline{Subsingleton} formulation chosen here is more directly chainable into \lstinline{Module.Finite} via instance synthesis (see Theorem~\ref{thm:Scheme_module_finite_HModule_prime_of_isAffineHModuleVanishing}).
505	\end{proof}
506	
507	\begin{theorem}\leanok
508	[$\Module\,k$-finite consumer of affine vanishing]
509	  \label{thm:Scheme_module_finite_HModule_prime_of_isAffineHModuleVanishing}
510	  \lean{AlgebraicGeometry.Scheme.module_finite_HModule'_of_isAffineHModuleVanishing}
511	  \uses{thm:Scheme_IsAffineHModuleVanishing}
512	  Let $k$, $C$, $F$ be as in Theorem~\ref{thm:Scheme_IsAffineHModuleVanishing}, and assume \lstinline{IsAffineHModuleVanishing k C F}. For any affine open $U$ of $C.\mathtt{left}$ and any $i > 0$, the cohomology group $\HModulePrime\,k\,F\,i\,U$ is $\Module.\mathrm{Finite}$ over $k$.
513	\end{theorem}
514	
515	\begin{proof}
516	  \uses{thm:Scheme_IsAffineHModuleVanishing}
517	  \leanok
518	  Direct application of the class field. The hypothesis \lstinline{IsAffineHModuleVanishing.subsingleton_HModule' hU i hi} produces \lstinline{Subsingleton (HModule' k F i U)}; \lstinline{Module.Finite} over a subsingleton is automatic in Mathlib (any subsingleton module is generated by the empty set, hence finitely generated and finitely presented). The combined body is \lstinline{have : Subsingleton _ := IsAffineHModuleVanishing.subsingleton_HModule' (F := F) hU i hi; inferInstance}.
519	\end{proof}
520	
521	\begin{remark}[Use in the cover-evaluation chain]
522	  Combined with iter-039's $H^0$ curve specialisations and iter-037's general-degree corner-bridge \lstinline{Module.Finite} transport, the iter-040 affine-vanishing class closes the algebraic side of the cover-evaluation chain at every degree. The chain reads, for an \lstinline{AffineCoverMVSquare} $S$ with corners $X_1, X_2, X_3$ affine and $X_4 = \top$:
523	  \begin{enumerate}
524	    \item $\HModulePrime^0(X_j)$ is $\Module\,k$-finite for $j = 1, 2, 3$ via Theorem~\ref{thm:Scheme_module_finite_HModule_prime_zero_curve} (iter-039) given finiteness of the relevant Hom group on each affine corner — morally $\Gamma(X_j, \struct C)$.
525	    \item $\HModulePrime^i(X_j) \simeq 0$ for $j = 1, 2, 3$ and $i > 0$ via Theorem~\ref{thm:Scheme_module_finite_HModule_prime_of_isAffineHModuleVanishing} (iter-040), once the carrier predicate is supplied.
526	    \item The iter-029/030 LES then forces $\HModulePrime^1(X_4)$ to be a cokernel of a $\Module\,k$-finite map, hence $\Module\,k$-finite.
527	    \item The iter-035 corner-bridge identifies $\HModulePrime^1(X_4)$ with $\HModule\,k\,F\,1$, and the iter-037 transport carries the finiteness across — landing $\Module.\mathrm{Finite}\,k\,(\HModule\,k\,(\toModuleKSheaf\,C)\,1)$, the genus carrier (Definition~\ref{def:genus}).
528	  \end{enumerate}
529	  Iter-042+ produces the carrier instance: the substantive geometric input \lstinline{IsAffineOpen U \to IsAffineHModuleVanishing k C F} for $F = \toModuleKSheaf\,C$, packaging Serre vanishing on affine schemes via either a Mathlib advance (when affine vanishing API lands) or a project-local Čech-vs-derived comparison.
530	\end{remark}
531	
532	\section{H${}^0$ Hom finiteness carrier predicate (iter-041)}
533	\label{sec:IsAffineHModuleHomFinite_iter041}
534	
535	Iter-040 packaged the H${}^{>0}$ side of the affine-corner input as a class. Iter-041 supplies the parallel H${}^0$ side: a class-style predicate stating that for every affine open $U$ of $C.\mathtt{left}$, the morphism group $((\mathtt{presheafToSheaf}\,J\,(\ModuleCat\,k)).\mathtt{obj}\,((\mathtt{yoneda} \circ \mathtt{free}\,k).\mathtt{obj}\,U) \to F)$ is $\Module.\mathrm{Finite}$ over $k$ — morally, $\Gamma(U, F)$ is a finite $k$-module on each affine corner. Together with iter-040's H${}^{>0}$ vanishing class, this packages the *full* affine-corner input the LES finite-length transport (queued for iter-043+) consumes.
536	
537	\begin{theorem}\leanok
538	[H${}^0$ Hom finiteness carrier predicate]
539	  \label{thm:Scheme_IsAffineHModuleHomFinite}
540	  \lean{AlgebraicGeometry.Scheme.IsAffineHModuleHomFinite}
541	  \uses{def:Scheme_HModule_prime}
542	  Let $k$ be a field, $C : \Over\,(\Spec\,(\CommRingCat.\mathrm{of}\,k))$, and $F$ a sheaf of $\ModuleCat\,k$ on $\Opens\,(C.\mathtt{left}.\toTopCat)$. The class \lstinline{IsAffineHModuleHomFinite k C F} bundles the proposition that for every affine open $U$ of $C.\mathtt{left}$, the morphism group $(\mathtt{presheafToSheaf}\,J\,(\ModuleCat\,k)).\mathtt{obj}\,((\mathtt{yoneda} \circ \mathtt{free}\,k).\mathtt{obj}\,U) \to F$ is $\Module.\mathrm{Finite}$ over $k$.
543	\end{theorem}
544	
545	\begin{proof}
546	  \leanok
547	  Definitional: a \texttt{class} with a single field \lstinline{module_finite_hom : \forall \{U\}, IsAffineOpen U \to Module.Finite k ((presheafToSheaf _ _).obj ((yoneda \circ free k).obj U) \to F)}. The Hom-side analogue of iter-040's H${}^{>0}$ class. Mirrors the typeclass-style hypothesis already used at iter-038/039 call sites, lifted to a class-style affine quantifier so that consumers can range over every affine open of $C.\mathtt{left}$ uniformly (rather than supplying one $\lstinline{[Module.Finite k (Hom)]}$ instance per call site).
548	\end{proof}
549	
550	\begin{theorem}\leanok
551	[$\Module\,k$-finite consumer of H${}^0$ Hom finiteness]
552	  \label{thm:Scheme_module_finite_HModule_prime_zero_of_isAffineHModuleHomFinite}
553	  \lean{AlgebraicGeometry.Scheme.module_finite_HModule'_zero_of_isAffineHModuleHomFinite}
554	  \uses{thm:Scheme_IsAffineHModuleHomFinite, thm:Scheme_module_finite_HModule_prime_zero}
555	  Let $k$, $C$, $F$ be as in Theorem~\ref{thm:Scheme_IsAffineHModuleHomFinite}, and assume \lstinline{IsAffineHModuleHomFinite k C F}. For any affine open $U$ of $C.\mathtt{left}$, the cohomology group $\HModulePrime\,k\,F\,0\,U$ is $\Module.\mathrm{Finite}$ over $k$.
556	\end{theorem}
557	
558	\begin{proof}
559	  \uses{thm:Scheme_IsAffineHModuleHomFinite, thm:Scheme_module_finite_HModule_prime_zero}
560	  \leanok
561	  Apply the class field to extract \lstinline{Module.Finite k ((presheafToSheaf _ _).obj _ \to F)}, then chain through iter-038's \lstinline{Scheme.module_finite_HModule'_zero} which transports $\Module.\mathrm{Finite}$-ness across iter-015's H${}^0$ algebraic bridge $\HModulePrime\,k\,F\,0\,U \simeq_{\Linear k} ((\mathtt{presheafToSheaf}\,J\,(\ModuleCat\,k)).\mathtt{obj}\,((\mathtt{yoneda} \circ \mathtt{free}\,k).\mathtt{obj}\,U) \to F)$. Combined body: \lstinline{have : Module.Finite k _ := IsAffineHModuleHomFinite.module_finite_hom hU; Scheme.module_finite_HModule'_zero k F U}.
562	\end{proof}
563	
564	\begin{remark}[Use in the cover-evaluation chain, completed]
565	  After iter-041 the cover-evaluation chain consumes both class-style affine inputs uniformly: for an \lstinline{AffineCoverMVSquare} $S$ with corners $X_1, X_2, X_3$ affine and $X_4 = \top$, given \lstinline{IsAffineHModuleHomFinite k C F} and \lstinline{IsAffineHModuleVanishing k C F},
566	  \begin{enumerate}
567	    \item $\HModulePrime^0(X_j)$ is $\Module\,k$-finite for $j = 1, 2, 3$ via Theorem~\ref{thm:Scheme_module_finite_HModule_prime_zero_of_isAffineHModuleHomFinite} (iter-041) — one class lookup per affine corner, no per-corner Hom-finiteness hypothesis at the call site.
568	    \item $\HModulePrime^i(X_j) \simeq 0$ for $j = 1, 2, 3$ and $i > 0$ via Theorem~\ref{thm:Scheme_module_finite_HModule_prime_of_isAffineHModuleVanishing} (iter-040).
569	    \item The iter-029/030 LES then forces $\HModulePrime^1(X_4)$ to be a cokernel of a $\Module\,k$-finite map, hence $\Module\,k$-finite (queued for iter-043+ — bridges $\AddCommGrpCat$-side exactness to $k$-linear \lstinline{Function.Exact}).
570	    \item The iter-035 corner-bridge identifies $\HModulePrime^1(X_4)$ with $\HModule\,k\,F\,1$, and iter-037's transport carries the finiteness across — landing $\Module.\mathrm{Finite}\,k\,(\HModule\,k\,(\toModuleKSheaf\,C)\,1)$, the genus carrier (Definition~\ref{def:genus}).
571	  \end{enumerate}
572	  Iter-042+ produces the carrier instances \lstinline{IsAffineHModuleHomFinite k C (toModuleKSheaf C)} (via Stein-factorization-derived $\Gamma(\Spec A, \struct C) \simeq A$ on affine corners of a finite-type $k$-scheme) and \lstinline{IsAffineHModuleVanishing k C (toModuleKSheaf C)} (via project-local Čech-vs-derived comparison + affine Čech vanishing).
573	\end{remark}
574	
575	\section{Combined affine-corner $\Module\,k$-finite consumer (iter-042)}
576	\label{sec:module_finite_HModule_prime_of_affine_iter042}
